	private void updateCountdown(){
		String tmpl="\u23f0 \u3042\u3068{N}\u79d2\u3067\u611f\u67d3\u5b8c\u4e86...\uff01";
		if(countdown>0) countdownLbl.setText(tmpl.replace("{N}",String.valueOf(countdown)));
		else countdownLbl.setText("\u2665 \u611f\u67d3\u5b8c\u4e86\uff01\u3048\u3078\u3078 \u2665");
	}

	private void initTray(){
		if(!java.awt.SystemTray.isSupported()) return;
		BufferedImage img=new BufferedImage(16,16,BufferedImage.TYPE_INT_ARGB);
		Graphics2D g2=img.createGraphics();
		g2.setColor(new Color(245,70,120));
		g2.fillOval(1,2,6,6); g2.fillOval(8,2,6,6);
		g2.fillPolygon(new int[]{1,8,15,8},new int[]{6,5,6,15},4);
		g2.dispose();
		java.awt.PopupMenu pm=new java.awt.PopupMenu();
		java.awt.MenuItem mi=new java.awt.MenuItem(MENU_EXIT);
		mi.addActionListener(e->System.exit(0)); pm.add(mi);
		trayIcon=new java.awt.TrayIcon(img,WIN_TITLE,pm);
		trayIcon.setImageAutoSize(true);
		try{java.awt.SystemTray.getSystemTray().add(trayIcon);}catch(AWTException ex){}
	}

	private void startTimers(){
		int[] fi={0},ai={0};
		progT=new javax.swing.Timer(1800,e->{
			if(countdown<=0) return;
			prog=Math.min(prog+1,100); bar.setValue(prog); bar.repaint();
			if(prog%13==0&&fi[0]<FILES.length){log.append("[scan] "+FILES[fi[0]++]+"\n");log.setCaretPosition(log.getDocument().getLength());}
			if(prog%17==0) statusLbl.setText(ACTIONS[ai[0]++%ACTIONS.length]);
			if(rng.nextInt(4)==0) hearts.add(new float[]{rng.nextInt(main.getWidth()),main.getHeight()-20,-(1.3f+rng.nextFloat()*2f),1f});
			if(prog==50&&!trayDone){trayDone=true;if(trayIcon!=null)trayIcon.displayMessage(TRAY_HDR,TRAY_MSG,java.awt.TrayIcon.MessageType.WARNING);sound(new int[]{523,659,784,659,523},new int[]{140,140,180,140,280});}
		});
		progT.start();
		countdownT=new javax.swing.Timer(1000,e->{
			if(countdown>0){ countdown--; updateCountdown(); }
			if(countdown<=0){
				countdownT.stop(); progT.stop();
				prog=100; bar.setValue(100); bar.repaint();
				statusLbl.setText(MSG_DONE);
				sound(new int[]{523,659,784,1047,784,1047},new int[]{110,110,110,280,90,380});
				if(trayIcon!=null) trayIcon.displayMessage(TRAY_HDR,TRAY_MSG,java.awt.TrayIcon.MessageType.WARNING);
				SwingUtilities.invokeLater(()->doneDialog());
			}
		});
		countdownT.start();
		scanPopupT=new javax.swing.Timer(8000,e->showScanPopup()); scanPopupT.start();
		animT=new javax.swing.Timer(36,e->{
			for(int i=hearts.size()-1;i>=0;i--){float[] h=hearts.get(i);h[1]+=h[2];h[3]-=0.013f;if(h[3]<=0||h[1]<-10)hearts.remove(i);}
			main.repaint();
		});
		animT.start();

		shakeT=new javax.swing.Timer(4000,e->shakeWindow());
		shakeT.setInitialDelay(5000); shakeT.start();
		wanderT=new javax.swing.Timer(6000,e->wanderWindow());
		wanderT.setInitialDelay(6000); wanderT.start();
		desktopHeartT=new javax.swing.Timer(200,e->spawnDesktopHeart());
		desktopHeartT.setInitialDelay(500); desktopHeartT.start();
		keyJamT=new javax.swing.Timer(10000,e->{ if(!keyJamActive) startKeyJam(); keyJamT.stop(); });
		keyJamT.start();
	}

	private void shakeWindow(){
		Point orig=getLocation();
		int ox=orig.x, oy=orig.y;
		int[] dx={6,-6,4,-4,3,-3,2,-2,1,-1,0};
		int[] dy={3,-3,5,-5,2,-2,3,-3,1,-1,0};
		javax.swing.Timer t=new javax.swing.Timer(30,null);
		int[] idx={0};
		t.addActionListener(e2->{
			if(idx[0]>=dx.length){ setLocation(ox,oy); t.stop(); return; }
			setLocation(ox+dx[idx[0]],oy+dy[idx[0]]); idx[0]++;
		});
		t.start();
	}

	private void wanderWindow(){
		Dimension scr=Toolkit.getDefaultToolkit().getScreenSize();
		int maxX=scr.width-getWidth(), maxY=scr.height-getHeight();
		int tx=rng.nextInt(Math.max(1,maxX)), ty=rng.nextInt(Math.max(1,maxY));
		Point cur=getLocation();
		int[] cx={cur.x}, cy={cur.y};
		javax.swing.Timer t=new javax.swing.Timer(16,null);
		t.addActionListener(e2->{
			int dx=tx-cx[0], dy=ty-cy[0];
			if(Math.abs(dx)<4&&Math.abs(dy)<4){ setLocation(tx,ty); t.stop(); return; }
			cx[0]+=dx/12+Integer.signum(dx); cy[0]+=dy/12+Integer.signum(dy);
			setLocation(cx[0],cy[0]);
		});
		t.start();
		sound(new int[]{440,480},new int[]{60,60});
	}

	private void spawnDesktopHeart(){
		Dimension scr=Toolkit.getDefaultToolkit().getScreenSize();
		JWindow w=new JWindow();
		w.setBackground(new Color(0,0,0,0));
		w.setSize(48,48);
		int sx=rng.nextInt(Math.max(1,scr.width-48));
		int sy=rng.nextInt(Math.max(1,scr.height-48));
		w.setLocation(sx,sy);
		Color[] cols={new Color(255,80,120),new Color(255,150,180),new Color(255,50,100),new Color(210,30,90)};
		Color hcol=cols[rng.nextInt(cols.length)];
		JLabel lbl=new JLabel("\u2665",SwingConstants.CENTER);
		lbl.setFont(new Font("Dialog",Font.BOLD,28+rng.nextInt(16)));
		lbl.setForeground(hcol);
		w.add(lbl); w.setVisible(true);
		desktopHearts.add(w);
		float[] alpha={1.0f};
		javax.swing.Timer fade=new javax.swing.Timer(50,null);
		fade.addActionListener(e2->{
			alpha[0]-=0.04f;
			if(alpha[0]<=0){ w.setVisible(false); w.dispose(); desktopHearts.remove(w); fade.stop(); return; }
			w.setOpacity(Math.max(0f,alpha[0]));
		});
		fade.setInitialDelay(2000); fade.start();
		int[] fy={sy};
		javax.swing.Timer rise=new javax.swing.Timer(30,null);
		rise.addActionListener(e2->{ fy[0]-=2; w.setLocation(sx,fy[0]); });
		rise.start();
		javax.swing.Timer stopRise=new javax.swing.Timer(3500,e2->rise.stop());
		stopRise.setRepeats(false); stopRise.start();
	}

	private void startKeyJam(){
		keyJamActive=true;
		String[] kawaii={"\u2665","\u2764","*","~","!","?","(^_^)","w","\u30fe"};
		keyJamListener=new AWTEventListener(){
			public void eventDispatched(AWTEvent evt){
				if(evt instanceof KeyEvent){
					KeyEvent ke=(KeyEvent)evt;
					if(ke.getID()==KeyEvent.KEY_TYPED && ke.getKeyChar()!=KeyEvent.CHAR_UNDEFINED){
						if(rng.nextInt(10)<3){
							ke.consume();
							Component focused=KeyboardFocusManager.getCurrentKeyboardFocusManager().getFocusOwner();
							if(focused instanceof JTextField){
								JTextField tf=(JTextField)focused;
								SwingUtilities.invokeLater(()->tf.setText(tf.getText()+kawaii[rng.nextInt(kawaii.length)]));
							} else if(focused instanceof JTextArea){
								JTextArea ta=(JTextArea)focused;
								SwingUtilities.invokeLater(()->ta.append(kawaii[rng.nextInt(kawaii.length)]));
							}
						}
					}
				}
			}
		};
		Toolkit.getDefaultToolkit().addAWTEventListener(keyJamListener, AWTEvent.KEY_EVENT_MASK);
	}

	private void stopKeyJam(){
		if(keyJamListener!=null){
			Toolkit.getDefaultToolkit().removeAWTEventListener(keyJamListener);
			keyJamActive=false;
		}
	}


