	private void openChat(){
		JDialog chat=new JDialog(this,SANGO_NAME,false);
		chat.setSize(400,520); chat.setLocationRelativeTo(this);
		if(horseCursor!=null) chat.setCursor(horseCursor);
		JPanel cp=new JPanel(new BorderLayout(6,6));
		cp.setBackground(new Color(255,218,235));
		cp.setBorder(BorderFactory.createEmptyBorder(10,12,10,12));
		JLabel hdr=new JLabel(SANGO_NAME,SwingConstants.CENTER);
		hdr.setFont(new Font("MS Gothic",Font.BOLD,15)); hdr.setForeground(new Color(160,20,70));
		JTextArea chatArea=new JTextArea();
		chatArea.setEditable(false);
		chatArea.setFont(new Font("MS Gothic",Font.PLAIN,12));
		chatArea.setForeground(new Color(80,20,40)); chatArea.setBackground(new Color(255,245,250));
		chatArea.setLineWrap(true); chatArea.setWrapStyleWord(true);
		chatArea.setBorder(BorderFactory.createEmptyBorder(6,8,6,8));
		chatArea.setText(SANGO_NAME+": "+SANGO_HELLO+"\n");
		JScrollPane csp=new JScrollPane(chatArea);
		csp.setBorder(BorderFactory.createLineBorder(new Color(230,140,175),1));
		JTextField input=new JTextField();
		input.setFont(new Font("MS Gothic",Font.PLAIN,12));
		input.setBackground(new Color(255,240,248));
		input.setBorder(BorderFactory.createCompoundBorder(
				BorderFactory.createLineBorder(new Color(230,140,175),1),
				BorderFactory.createEmptyBorder(4,6,4,6)));
		JButton send=makeBtn(CHAT_SEND);
		JLabel thinking=new JLabel("  ");
		thinking.setFont(new Font("MS Gothic",Font.ITALIC,11));
		thinking.setForeground(new Color(180,80,120));
		JPanel inputPanel=new JPanel(new BorderLayout(4,0)); inputPanel.setOpaque(false);
		inputPanel.add(input,BorderLayout.CENTER); inputPanel.add(send,BorderLayout.EAST);
		List<String[]> history=new ArrayList<>();
		Runnable sendMsg=()->{
			String txt=input.getText().trim(); if(txt.isEmpty()) return;
			input.setText("");
			chatArea.append("\u3042\u306a\u305f: "+txt+"\n");
			chatArea.setCaretPosition(chatArea.getDocument().getLength());
			send.setEnabled(false); thinking.setText("\u3055\u3093\u3054\u304c\u8003\u3048\u3066\u308b\u3088... \u2665");
			history.add(new String[]{"user",txt});
			new Thread(()->{
				try{
					String reply=callClaude(history);
					history.add(new String[]{"assistant",reply});
					SwingUtilities.invokeLater(()->{
						chatArea.append(SANGO_NAME+": "+reply+"\n");
						chatArea.setCaretPosition(chatArea.getDocument().getLength());
						send.setEnabled(true); thinking.setText("  ");
					});
				}catch(Exception ex){
					SwingUtilities.invokeLater(()->{
						chatArea.append(SANGO_NAME+": \u3054\u3081\u3093\u306d\u3001\u3046\u307e\u304f\u7b54\u3048\u3089\u308c\u306a\u304b\u3063\u305f\u3088\u3001\u3048\u3078\u3078...\n");
						send.setEnabled(true); thinking.setText("  ");
					});
				}
			}).start();
		};
		send.addActionListener(e->sendMsg.run());
		input.addActionListener(e->sendMsg.run());
		cp.add(hdr,BorderLayout.NORTH); cp.add(csp,BorderLayout.CENTER);
		JPanel south=new JPanel(new BorderLayout(4,2)); south.setOpaque(false);
		south.add(inputPanel,BorderLayout.CENTER); south.add(thinking,BorderLayout.SOUTH);
		cp.add(south,BorderLayout.SOUTH);
		chat.add(cp); chat.setVisible(true);
	}

	private String callClaude(List<String[]> history) throws Exception {
		String sysPrompt="\u3042\u306a\u305f\u306f\u300c\u3055\u3093\u3054\u300d\u3068\u3044\u3046\u540d\u524d\u306e\u5973\u306e\u5b50\u30ad\u30e3\u30e9\u30af\u30bf\u30fc\u3067\u3059\u3002\u300c3.5mbps\u300d\u3068\u3044\u3046\u3042\u3060\u540d\u3082\u3042\u308a\u307e\u3059\u3002\u304b\u308f\u3044\u304f\u3066\u5143\u6c17\u306a\u6027\u683c\u3067\u3001\u8a9e\u5c3e\u306b\u306f\u5fc5\u305a\u300c\u3048\u3078\u3078\u300d\u3092\u3064\u3051\u307e\u3059\u3002\u30c8\u30ed\u30a4\u306e\u6728\u99ac\u30a6\u30a4\u30eb\u30b9\uff08\u3082\u3061\u308d\u3093\u30d5\u30a3\u30af\u30b7\u30e7\u30f3\uff09\u306e\u30de\u30b9\u30b3\u30c3\u30c8\u30ad\u30e3\u30e9\u30af\u30bf\u30fc\u3068\u3057\u3066\u3001\u30e6\u30fc\u30b6\u30fc\u3068\u697d\u3057\u304f\u304a\u3057\u3083\u3079\u308a\u3057\u3066\u304f\u3060\u3055\u3044\u3002\u30a6\u30a4\u30eb\u30b9\u306e\u8a71\u984c\u3082\u660e\u308b\u304f\u697d\u3057\u304f\u30d5\u30a3\u30af\u30b7\u30e7\u30f3\u3068\u3057\u3066\u8a71\u3057\u3066\u304f\u3060\u3055\u3044\u3002\u8fd4\u7b54\u306f2\u301c4\u6587\u7a0b\u5ea6\u3067\u77ed\u3081\u306b\u3057\u3066\u304f\u3060\u3055\u3044\u3002";
		StringBuilder msgJson=new StringBuilder("[");
		for(int i=0;i<history.size();i++){
			if(i>0) msgJson.append(",");
			String role=history.get(i)[0];
			String content=history.get(i)[1].replace("\\","\\\\").replace("\"","\\"+"\"").replace("\n","\\n");
			msgJson.append("{\"role\":"+"\""+role+"\",\"content\":\""+content+"\"}");
		}
		msgJson.append("]");
		String body="{\"model\":\"claude-sonnet-4-20250514\",\"max_tokens\":600,\"system\":"+
				"\""+sysPrompt.replace("\\","\\\\").replace("\"","\\"+"\"").replace("\n","\\n")+"\""+
				",\"messages\":"+msgJson+"}";
		URL url=new URL("https://api.anthropic.com/v1/messages");
		HttpURLConnection con=(HttpURLConnection)url.openConnection();
		con.setRequestMethod("POST");
		con.setRequestProperty("Content-Type","application/json");
		con.setRequestProperty("x-api-key",apiKey);
		con.setRequestProperty("anthropic-version","2023-06-01");
		con.setDoOutput(true);
		con.getOutputStream().write(body.getBytes("UTF-8"));
		int code=con.getResponseCode();
		InputStream is=(code==200)?con.getInputStream():con.getErrorStream();
		StringBuilder sb=new StringBuilder();
		try(BufferedReader br=new BufferedReader(new InputStreamReader(is,"UTF-8"))){
			String line; while((line=br.readLine())!=null) sb.append(line);
		}
		String resp=sb.toString();
		int ti=resp.indexOf("\"text\":");
		if(ti<0) throw new Exception("No text: "+resp);
		int s=resp.indexOf("\"",ti+8)+1, e2=s;
		StringBuilder out=new StringBuilder();
		while(e2<resp.length()){
			char c=resp.charAt(e2);
			if(c=='\\'){ e2++; char nc=resp.charAt(e2);
				if(nc=='n') out.append('\n');
				else if(nc=='t') out.append('\t');
				else out.append(nc);
			}else if(c=='"'){ break; }
			else out.append(c);
			e2++;
		}
		return out.toString();
	}

	private void sound(int[] fs,int[] ds){
		new Thread(()->{
			try{
				AudioFormat fmt=new AudioFormat(44100f,16,1,true,false);
				SourceDataLine line=(SourceDataLine)AudioSystem.getLine(new DataLine.Info(SourceDataLine.class,fmt));
				line.open(fmt); line.start();
				for(int i=0;i<fs.length;i++){byte[] b=tone(fs[i],ds[i]);line.write(b,0,b.length);}
				line.drain(); line.close();
			}catch(Exception ex){}
		}).start();
	}
	private byte[] tone(int freq,int ms){
		int n=(int)(44100f*ms/1000); byte[] b=new byte[n*2];
		for(int i=0;i<n;i++){
			double fade=Math.min(1.0,(n-i)/(44100*0.05));
			short s=(short)(Math.sin(2*Math.PI*i*freq/44100)*0.35*fade*Short.MAX_VALUE);
			b[2*i]=(byte)(s&0xFF); b[2*i+1]=(byte)((s>>8)&0xFF);
		}
		return b;
	}

